function PnLDashboard({ financials, properties }) {
  const { div, h1, h2, span, table, thead, tbody, tr, th, td } = tags;
  const [dateRange, setDateRange] = createSignal('ytd');
  const [propertyFilter, setPropertyFilter] = createSignal('all');

  const data = propertyFilter() === 'all' ? financials : financials.filter(f => f.propertyId === propertyFilter());

  const grossIncome = data.reduce((sum, f) => sum + f.income, 0);
  const totalExpenses = data.reduce((sum, f) => sum + f.expenses, 0);
  const noi = grossIncome - totalExpenses;
  const noiMargin = Math.round((noi / grossIncome) * 100) || 0;
  const debtService = data.reduce((sum, f) => sum + (f.debtService || 0), 0);
  const cashFlow = noi - debtService;

  const incomeCategories = [
    { name: 'Rental Income', amount: data.reduce((sum, f) => sum + f.rentalIncome, 0), percent: 85 },
    { name: 'Late Fees', amount: data.reduce((sum, f) => sum + (f.lateFees || 0), 0), percent: 5 },
    { name: 'Other Income', amount: data.reduce((sum, f) => sum + (f.otherIncome || 0), 0), percent: 10 }
  ];

  const expenseCategories = [
    { name: 'Mortgage/Debt', amount: data.reduce((sum, f) => sum + (f.mortgage || 0), 0) },
    { name: 'Insurance', amount: data.reduce((sum, f) => sum + (f.insurance || 0), 0) },
    { name: 'Property Taxes', amount: data.reduce((sum, f) => sum + (f.taxes || 0), 0) },
    { name: 'Maintenance', amount: data.reduce((sum, f) => sum + (f.maintenance || 0), 0) },
    { name: 'Utilities', amount: data.reduce((sum, f) => sum + (f.utilities || 0), 0) },
    { name: 'Management Fees', amount: data.reduce((sum, f) => sum + (f.management || 0), 0) },
    { name: 'Other', amount: data.reduce((sum, f) => sum + (f.otherExpenses || 0), 0) }
  ].sort((a, b) => b.amount - a.amount);

  return div({ class: css('_flex _col _gap6') },
    div({ class: css('_flex _jcsb _aic') },
      h1({ class: css('_heading3') }, 'Financial Overview'),
      div({ class: css('_flex _gap2') },
        Select({ value: dateRange(), onchange: e => setDateRange(e.target.value) },
          tags.option({ value: 'mtd' }, 'Month to Date'),
          tags.option({ value: 'qtd' }, 'Quarter to Date'),
          tags.option({ value: 'ytd' }, 'Year to Date'),
          tags.option({ value: 'custom' }, 'Custom Range')
        ),
        Select({ value: propertyFilter(), onchange: e => setPropertyFilter(e.target.value) },
          tags.option({ value: 'all' }, 'All Properties'),
          ...properties.map(p => tags.option({ value: p.id }, p.name))
        ),
        Button({ variant: 'outline' }, icon('download'), 'Export')
      )
    ),
    div({ class: css('_grid _cols4 _gap4') },
      div({ class: css('estate-card-metric _p4') },
        span({ class: css('_heading2 _block _fgsuccess') }, `$${grossIncome.toLocaleString()}`),
        span({ class: css('_textsm _fgmuted') }, 'Gross Income')
      ),
      div({ class: css('estate-card-metric _p4') },
        span({ class: css('_heading2 _block _fgdanger') }, `$${totalExpenses.toLocaleString()}`),
        span({ class: css('_textsm _fgmuted') }, 'Total Expenses')
      ),
      div({ class: css('estate-card-metric _p4') },
        span({ class: css('_heading2 _block') }, `$${noi.toLocaleString()}`),
        span({ class: css('_textsm _fgmuted') }, `NOI (${noiMargin}% margin)`)
      ),
      div({ class: css('estate-card-metric _p4') },
        span({ class: css(`_heading2 _block ${cashFlow >= 0 ? '_fgsuccess' : '_fgdanger'}`) }, `$${cashFlow.toLocaleString()}`),
        span({ class: css('_textsm _fgmuted') }, 'Cash Flow')
      )
    ),
    div({ class: css('_grid _cols2 _gap6') },
      div({ class: css('estate-card _p4') },
        h2({ class: css('_heading5 _mb4') }, 'Income Breakdown'),
        div({ class: css('_flex _col _gap3') },
          ...incomeCategories.map(cat =>
            div({ class: css('_flex _jcsb _aic') },
              span({ class: css('_textsm') }, cat.name),
              span({ class: css('_font500') }, `$${cat.amount.toLocaleString()}`)
            )
          ),
          div({ class: css('_flex _jcsb _aic _pt3 _borderT _font500') },
            span({}, 'Total'),
            span({ class: css('_fgsuccess') }, `$${grossIncome.toLocaleString()}`)
          )
        )
      ),
      div({ class: css('estate-card _p4') },
        h2({ class: css('_heading5 _mb4') }, 'Expense Breakdown'),
        div({ class: css('_flex _col _gap3') },
          ...expenseCategories.slice(0, 6).map(cat =>
            div({ class: css('_flex _jcsb _aic') },
              span({ class: css('_textsm') }, cat.name),
              span({ class: css('_font500') }, `$${cat.amount.toLocaleString()}`)
            )
          ),
          div({ class: css('_flex _jcsb _aic _pt3 _borderT _font500') },
            span({}, 'Total'),
            span({ class: css('_fgdanger') }, `$${totalExpenses.toLocaleString()}`)
          )
        )
      )
    ),
    div({ class: css('estate-card _p4') },
      h2({ class: css('_heading5 _mb4') }, 'P&L by Property'),
      div({ class: css('estate-table _overflow[auto]') },
        table({ class: css('_wfull') },
          thead({},
            tr({ class: css('_bgSurface') },
              th({ class: css('_p3 _textleft _font500') }, 'Property'),
              th({ class: css('_p3 _tr _font500') }, 'Income'),
              th({ class: css('_p3 _tr _font500') }, 'Expenses'),
              th({ class: css('_p3 _tr _font500') }, 'NOI'),
              th({ class: css('_p3 _tc _font500') }, 'Margin'),
              th({ class: css('_p3 _tr _font500') }, 'Cash Flow')
            )
          ),
          tbody({},
            ...properties.map((p, i) => {
              const pData = financials.filter(f => f.propertyId === p.id);
              const pIncome = pData.reduce((sum, f) => sum + f.income, 0);
              const pExpenses = pData.reduce((sum, f) => sum + f.expenses, 0);
              const pNoi = pIncome - pExpenses;
              const pMargin = Math.round((pNoi / pIncome) * 100) || 0;
              const pDebt = pData.reduce((sum, f) => sum + (f.debtService || 0), 0);
              const pCashFlow = pNoi - pDebt;
              return tr({ class: css(i % 2 === 0 ? '' : '_bgSurfaceRaised') },
                td({ class: css('_p3 _font500') }, p.name),
                td({ class: css('_p3 _tr _fgsuccess') }, `$${pIncome.toLocaleString()}`),
                td({ class: css('_p3 _tr _fgdanger') }, `$${pExpenses.toLocaleString()}`),
                td({ class: css('_p3 _tr _font500') }, `$${pNoi.toLocaleString()}`),
                td({ class: css('_p3 _tc') }, `${pMargin}%`),
                td({ class: css(`_p3 _tr _font500 ${pCashFlow >= 0 ? '_fgsuccess' : '_fgdanger'}`) }, `$${pCashFlow.toLocaleString()}`)
              );
            })
          )
        )
      )
    )
  );
}

