      span({ class: css('_heading6') }, 'Financials'),
      span({ class: css('_textsm _fgmuted') }, 'This Month')
    ),
    div({ class: css('_grid _cols2 _gap4') },
      div({},
        span({ class: css('_heading4 _block _fgsuccess') }, `$${income.toLocaleString()}`),
        span({ class: css('_textxs _fgmuted') }, 'Income')
      ),
      div({},
        span({ class: css('_heading4 _block _fgdanger') }, `$${expenses.toLocaleString()}`),
        span({ class: css('_textxs _fgmuted') }, 'Expenses')
      ),
      div({},
        span({ class: css('_heading4 _block') }, `$${noi.toLocaleString()}`),
        span({ class: css('_textxs _fgmuted') }, `NOI (${noiMargin}%)`)
      ),
      div({},
        span({ class: css(`_heading4 _block ${cashFlow >= 0 ? '_fgsuccess' : '_fgdanger'}`) }, `$${cashFlow.toLocaleString()}`),
        span({ class: css('_textxs _fgmuted') }, 'Cash Flow')
      )
    )
  );
}

